```lean
import Mathlib.Tactic

variable (n : Nat) -- The nondeterministic input

-- Simulates the first loop: while(x>0) { x--; y++; }
-- Input state: (x_in, y_in, z_in) where x_in = n
-- Output state: (x_out, y_out, z_out)
def loop1_trans (x_in y_in z_in : Nat) : Nat × Nat × Nat :=
  if x_in == 0 then (x_in, y_in, z_in)
  else loop1_trans (x_in - 1) (y_in + 1) z_in

-- Simulates the assignment z = y
def assign_z_eq_y (x y z : Nat) : Nat × Nat × Nat :=
  (x, y, y)

-- Simulates the second loop: while(z>0) { x++; z--; }
-- Input state: (x_in, y_in, z_in) where z_in = n
-- Output state: (x_out, y_out, z_out)
def loop2_trans (x_in y_in z_in : Nat) : Nat × Nat × Nat :=
  if z_in == 0 then (x_in, y_in, z_in)
  else loop2_trans (x_in + 1) y_in (z_in - 1)

-- Simulates the third loop: while(y>0) { y--; z++; }
-- Input state: (x_in, y_in, z_in) where y_in = n
-- Output state: (x_out, y_out, z_out)
def loop3_trans (x_in y_in z_in : Nat) : Nat × Nat × Nat :=
  if y_in == 0 then (x_in, y_in, z_in)
  else loop3_trans x_in (y_in - 1) (z_in + 1)

-- The sequence of transformations
-- Initial state: (n, 0, 0) for (x, y, z)
-- Let's call the state (x, y, z)
--
-- 1. x = n, y = 0, z = 0
--    State: (n, 0, 0)
--
-- 2. First loop: while(x>0) { x--; y++; }
--    This loop effectively sets x to 0 and y to its initial value of x.
--    If initial x is n, then after this loop x=0, y=n.
--    (x', y', z') = loop1_trans n 0 0 = (0, n, 0)
--
-- 3. z = y;
--    (x'', y'', z'') = assign_z_eq_y x' y' z' = assign_z_eq_y 0 n 0 = (0, n, n)
--
-- 4. Second loop: while(z>0) { x++; z--; }
--    This loop effectively sets z to 0 and x to its initial value of z.
--    Initial z is n. So after this loop z=0, x=n.
--    (x''', y''', z''') = loop2_trans 0 n n = (n, n, 0)
--
-- 5. Third loop: while(y>0) { y--; z++; }
--    This loop effectively sets y to 0 and z to its initial value of y.
--    Initial y is n. So after this loop y=0, z=n.
--    (x'''', y'''', z'''') = loop3_trans n n 0 = (n, 0, n)
--
-- 6. Fourth loop: while(x>0) { x--; y++; }
--    This loop effectively sets x to 0 and y to its initial value of x.
--    Initial x is n. So after this loop x=0, y=n.
--    (x5, y5, z5) = loop4_trans n 0 n.
--    We need loop4_trans. It's the same as loop1_trans but with different variable names
```

